def gen(rng, size):
    n = max(1, min(size, 10000))
    vals = [rng.randint(1, 100)]
    # build a random shaped tree as a BFS array with possible nulls
    arr = [rng.randint(1, 100)]
    count = 1
    i = 0
    while count < n and i < len(arr):
        if arr[i] is not None:
            for _ in range(2):
                if count < n and rng.random() < 0.85:
                    arr.append(rng.randint(1, 100))
                    count += 1
                else:
                    arr.append(None)
        i += 1
    # trim trailing nulls
    while arr and arr[-1] is None:
        arr.pop()
    return [arr]

