class Solution:
    def deepestLeavesSum(self, root):
        best_depth = -1
        best_sum = 0
        stack = [(root, 0)]
        while stack:
            node, d = stack.pop()
            if not node:
                continue
            if d > best_depth:
                best_depth = d
                best_sum = node.val
            elif d == best_depth:
                best_sum += node.val
            stack.append((node.left, d + 1))
            stack.append((node.right, d + 1))
        return best_sum

