class Solution:
    def deepestLeavesSum(self, root):
        from collections import deque
        q = deque([root])
        total = 0
        while q:
            total = 0
            for _ in range(len(q)):
                node = q.popleft()
                total += node.val
                if node.left:
                    q.append(node.left)
                if node.right:
                    q.append(node.right)
        return total

