var deepestLeavesSum = function(root) {
    let q = [root];
    let total = 0;
    while (q.length) {
        total = 0;
        const next = [];
        for (const node of q) {
            total += node.val;
            if (node.left) next.push(node.left);
            if (node.right) next.push(node.right);
        }
        q = next;
    }
    return total;
};
